-- Schema for Domain: scheduling | Business: Media_Broadcasting | Version: v2_mvm
-- Generated on: 2026-06-23 04:24:42

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `vibe_media_broadcasting_v1`.`scheduling` COMMENT 'Owns the Electronic Program Guide (EPG) and all playout scheduling logic for linear broadcast channels and on-demand programming windows. Manages dayparts, program rundowns, linear channel grids, ad pod placement, SCTE-35 cue markers, simulcast configurations, and automated schedule generation. Drives Ericsson MediaFirst automation for channel playout and failover, ensuring compliance with must-carry and blackout obligations.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`channel` (
    `channel_id` BIGINT COMMENT 'Unique surrogate identifier for each linear broadcast channel record. Primary key for the channel master data product within the scheduling domain.',
    `genre_id` BIGINT COMMENT 'Foreign key linking to content.genre. Business justification: channel carries a denormalized plain genre text column. Linking to content.genre normalizes channel genre classification, enabling genre-based content acquisition alignment, scheduling affinity repo',
    `ad_break_duration_sec` STRING COMMENT 'Default duration in seconds of a standard ad pod (ad break) for this channel. Used by Wide Orbit traffic system for ad scheduling, inventory management, and avail calculation. Typical values are 120 (2 minutes) or 180 (3 minutes).',
    `blackout_enabled` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions are applicable to this channel. When true, blackout rules must be enforced during playout and OTT delivery to restrict content in specific geographic markets per rights agreements.',
    `broadcast_timezone` STRING COMMENT 'IANA timezone identifier for the channels primary broadcast timezone (e.g., America/New_York, Europe/London). Governs daypart definitions, schedule generation, and EPG time display for the channels primary market.',
    `call_sign` STRING COMMENT 'Officially assigned broadcast call sign (e.g., WABC, KNBC) that uniquely identifies the station with the regulatory authority. Serves as the primary external business identifier for the channel as registered with the FCC or Ofcom.. Valid values are `^[A-Z0-9-]{2,10}$`',
    `carriage_fee_usd` DECIMAL(18,2) COMMENT 'The per-subscriber monthly carriage fee in US dollars charged to MVPDs and vMVPDs for distributing this channel. Commercially sensitive financial data used in revenue assurance, financial reconciliation in SAP S/4HANA, and EBITDA reporting.',
    `cdn_origin_url` STRING COMMENT 'The origin ingest URL configured in Akamai CDN for this channels live stream delivery. Used for OTT/streaming distribution, ABR (Adaptive Bitrate Streaming) packaging, and CDN cache configuration.',
    `channel_type` STRING COMMENT '',
    `content_rating_system` STRING COMMENT 'Default content advisory rating applied to the channels programming under the applicable rating system (e.g., US TV Parental Guidelines). Drives V-chip compliance, parental control enforcement, and COPPA-regulated childrens content restrictions.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the country where the channel is licensed and originates its broadcast signal (e.g., USA, GBR, DEU). Used for regulatory jurisdiction determination, rights windowing, and blackout rule enforcement.. Valid values are `^[A-Z]{3}$`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this channel record was first created in the system of record. Used for data lineage, audit trail, and record lifecycle tracking in the Silver Layer lakehouse.',
    `dai_enabled` BOOLEAN COMMENT 'Indicates whether Dynamic Ad Insertion (DAI) is active for this channel, enabling server-side ad replacement for OTT/streaming delivery. Drives ad operations workflow in Wide Orbit and integration with DAI platforms.',
    `decommission_date` DATE COMMENT 'The date on which this channel was or is scheduled to be permanently decommissioned and removed from broadcast. Nullable for active channels. Used for lifecycle management, licence surrender, and EPG removal planning.',
    `drm_enabled` BOOLEAN COMMENT 'Indicates whether Digital Rights Management (DRM) encryption is applied to this channels content stream for OTT/streaming delivery. Drives content protection configuration in Akamai CDN and subscriber entitlement enforcement in Zuora.',
    `epg_enabled` BOOLEAN COMMENT 'Indicates whether this channel is published to the Electronic Program Guide (EPG) for audience-facing schedule display. Channels under testing or decommissioned may be excluded from EPG publication.',
    `hls_stream_url` STRING COMMENT 'The HLS (HTTP Live Streaming) manifest URL for this channels live stream, used for Apple device and browser-based OTT delivery via Akamai CDN. Supports ABR (Adaptive Bitrate Streaming) for adaptive quality delivery.',
    `launch_date` DATE COMMENT 'The date on which this channel first went live and began broadcasting. Used for channel lifecycle tracking, anniversary reporting, regulatory licence history, and audience growth analytics.',
    `logical_channel_number` STRING COMMENT 'The numeric channel position assigned to this channel in the Electronic Program Guide (EPG) and set-top box channel lineup. Used by MVPDs and vMVPDs for channel navigation and must-carry compliance reporting.',
    `max_ad_load_pct` DECIMAL(18,2) COMMENT 'Maximum percentage of total broadcast hour that may be allocated to advertising on this channel. Governs inventory capacity planning, FCC commercial limits compliance (childrens programming), and upfront/scatter market sales commitments.',
    `mpeg_dash_stream_url` STRING COMMENT 'The MPEG-DASH (Dynamic Adaptive Streaming over HTTP) manifest URL for this channels live stream, used for Android, Smart TV, and cross-platform OTT delivery via Akamai CDN.',
    `must_carry_status` BOOLEAN COMMENT 'Indicates whether this channel is subject to must-carry obligations requiring MVPDs to include it in their channel lineup. Drives compliance reporting and carriage fee negotiations.',
    `network_name` STRING COMMENT 'Human-readable name of the broadcast network or channel brand (e.g., CNN, BBC One, ESPN). Used as the primary identity label for display in EPG, scheduling tools, and audience-facing interfaces.',
    `playout_automation_enabled` BOOLEAN COMMENT 'Indicates whether the channel is configured for automated playout via Ericsson MediaFirst. When true, schedule execution, ad insertion cues, and failover are handled automatically. When false, manual playout operation is required.',
    `primary_language` STRING COMMENT 'ISO 639-1/639-2 language code representing the primary audio language of the channels programming (e.g., en for English, es for Spanish, fra for French). Used for EPG metadata, accessibility compliance, and audience targeting.. Valid values are `^[a-z]{2,3}$`',
    `resolution_profile` STRING COMMENT 'Video resolution classification of the channel output. SD (Standard Definition), HD (High Definition 1080i/720p), UHD (Ultra High Definition 4K/8K). Determines encoding profiles, CDN delivery tiers, and subscriber package eligibility.. Valid values are `SD|HD|UHD|4K`',
    `retransmission_consent_required` BOOLEAN COMMENT 'Indicates whether this channel requires retransmission consent from MVPDs before rebroadcasting. Drives carriage fee negotiations and compliance with FCC retransmission consent rules.',
    `scte35_enabled` BOOLEAN COMMENT 'Indicates whether SCTE-35 digital program insertion cue markers are active on this channel for Dynamic Ad Insertion (DAI). SCTE-35 signals define ad pod boundaries and splice points used by Wide Orbit traffic system and DAI platforms.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `transmission_standard` STRING COMMENT '',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this channel record was most recently modified. Used for change data capture (CDC), incremental ETL processing, and audit trail compliance in the Databricks Silver Layer.',
    CONSTRAINT pk_channel PRIMARY KEY(`channel_id`)
) COMMENT 'Master record for each linear broadcast channel — capturing network identity, call sign, transmission standard (ATSC, DVB-T/T2, QAM), logical channel number, language, resolution profile (SD/HD/UHD), and playout automation linkage to Ericsson MediaFirst. Serves as the SSOT for channel identity referenced by program schedules, EPG entries, playout events, and simulcast configurations within this domain. Supports workload modes: Linear|FAST|MVPD.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`daypart` (
    `daypart_id` BIGINT COMMENT 'Primary key for daypart',
    `ad_pod_max_count` STRING COMMENT 'The maximum number of ad pods (commercial breaks) permitted per hour within this daypart. Used by Wide Orbit for ad scheduling capacity planning and by Ericsson MediaFirst for playout rundown validation. Supports FCC commercial time compliance monitoring.',
    `ad_pod_max_duration_seconds` STRING COMMENT 'The maximum allowable total duration in seconds for an ad pod (group of ads in a break) within this daypart. Governs commercial break length limits enforced by Ericsson MediaFirst playout automation and Wide Orbit ad scheduling. Aligns with FCC commercial time limits for childrens programming dayparts.',
    `applicable_days` STRING COMMENT 'Pipe-delimited list of days of the week on which this daypart definition applies, using three-letter abbreviations (e.g., MON|TUE|WED|THU|FRI for weekday dayparts, SAT|SUN for weekend). Governs schedule generation in Ericsson MediaFirst and ad inventory availability in Wide Orbit. [ENUM-REF-CANDIDATE: MON|TUE|WED|THU|FRI|SAT|SUN — promote to reference product]',
    `avg_audience_000` DECIMAL(18,2) COMMENT 'The average audience size in thousands of viewers (000s) expected during this daypart, based on Nielsen Media Research Platform historical ratings data. Used as the principal quantitative measurement of daypart audience value for ad sales, GRP calculations, and content scheduling decisions.',
    `base_cpm_usd` DECIMAL(18,2) COMMENT 'The baseline CPM (Cost Per Mille) rate in US dollars for advertising inventory sold within this daypart, before application of the rate_multiplier or audience demographic adjustments. Represents the floor pricing reference used in Salesforce Media Cloud upfront and scatter market proposals.',
    `blackout_eligible` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions can be applied to content scheduled within this daypart. When True, blackout rules (e.g., sports rights geographic exclusivity) may be enforced by the distribution platform. Aligns with must-carry and retransmission consent obligations.',
    `content_rating_restriction` STRING COMMENT 'The maximum permissible TV content rating (per MPA/TV Parental Guidelines) for programming scheduled within this daypart. Enforces content appropriateness standards — e.g., Prime Time may allow up to TV-14, while Childrens dayparts are restricted to TV-Y or TV-Y7. Used by Ericsson MediaFirst for schedule validation.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `coppa_restricted` BOOLEAN COMMENT 'Indicates whether this daypart is subject to COPPA (Childrens Online Privacy Protection Act) restrictions due to programming directed at children under 13. When True, audience data collection, behavioral targeting, and ad pod duration limits are governed by COPPA compliance rules and FCC childrens television regulations.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this daypart record was first created in the scheduling domain data product. Supports audit trail, data lineage tracking, and Silver layer ingestion reconciliation in the Databricks Lakehouse.',
    `dai_eligible` BOOLEAN COMMENT 'Indicates whether this daypart is eligible for Dynamic Ad Insertion (DAI) on OTT and streaming platforms. When True, ad pods within this daypart can be dynamically replaced with targeted ads during streaming delivery through Akamai CDN, enabling addressable advertising revenue.',
    `daypart_description` STRING COMMENT 'Free-text narrative description of the daypart, including its programming characteristics, audience profile, and scheduling context. Used for internal documentation, Salesforce Media Cloud proposal narratives, and EPG metadata. Example: Prime Time (8PM-11PM) — highest-rated evening programming block targeting Adults 18-49.',
    `duration_minutes` STRING COMMENT 'Total duration of the daypart window expressed in minutes. Derived from start_time and end_time boundaries but stored explicitly for scheduling calculations, ad inventory capacity planning, and rate card generation in Wide Orbit.',
    `effective_from` DATE COMMENT 'The calendar date from which this daypart definition becomes effective for scheduling and ad sales operations. Supports versioned daypart definitions where boundaries or rates change seasonally or following regulatory updates. Used in Wide Orbit and Ericsson MediaFirst schedule generation.',
    `effective_until` DATE COMMENT 'The calendar date on which this daypart definition expires and is no longer applicable for scheduling and ad sales. Null indicates an open-ended definition with no planned expiry. Supports seasonal daypart adjustments (e.g., summer schedule changes) and regulatory compliance updates.',
    `end_time` TIMESTAMP COMMENT 'The clock time (HH:mm:ss, 24-hour or extended broadcast-day format) at which the daypart ends. Supports broadcast day overflow notation (e.g., 25:59:59 for content airing past midnight within the same broadcast day). Paired with start_time to define the daypart boundary.',
    `epg_display_order` STRING COMMENT 'The sequential display order of this daypart within the Electronic Program Guide (EPG) channel grid, used by Ericsson MediaFirst for schedule presentation and by digital EPG distribution systems. Lower values appear earlier in the broadcast day display.',
    `grp_index` DECIMAL(18,2) COMMENT 'The GRP (Gross Rating Point) index value representing the expected audience delivery weight for this daypart relative to the total broadcast day. Used in media planning, upfront negotiations, and scatter market pricing. Sourced from Nielsen Media Research Platform ratings data.',
    `hut_level` DECIMAL(18,2) COMMENT 'The HUT (Homes Using Television) percentage representing the proportion of TV households actively viewing during this daypart. A key audience measurement metric sourced from Nielsen Media Research Platform, used to benchmark daypart audience potential and inform ad pricing.',
    `makegood_eligible` BOOLEAN COMMENT 'Indicates whether compensatory ad spots (makegoods) can be scheduled within this daypart to fulfill underdelivered audience guarantees from other dayparts. Governs Wide Orbit makegood scheduling logic and Salesforce Media Cloud campaign reconciliation workflows.',
    `daypart_name` STRING COMMENT 'Human-readable label for the daypart segment as displayed in the Electronic Program Guide (EPG), ad sales proposals, and scheduling interfaces. Examples: Early Morning, Morning Drive, Daytime, Prime Time, Late Fringe, Overnight.',
    `rate_multiplier` DECIMAL(18,2) COMMENT 'Pricing multiplier applied to the base CPM (Cost Per Mille) rate card for ad inventory sold within this daypart. A value of 1.0000 represents the base rate; Prime Time typically carries a multiplier greater than 1.0 (e.g., 2.5000), while Overnight may be below 1.0 (e.g., 0.3000). Used in Salesforce Media Cloud proposal generation and Wide Orbit billing.',
    `scatter_eligible` BOOLEAN COMMENT 'Indicates whether unsold ad inventory within this daypart is available for scatter market (last-minute) sales. Governs Wide Orbit inventory availability rules for short-notice ad placement and makegood scheduling.',
    `scte35_cue_enabled` BOOLEAN COMMENT 'Indicates whether SCTE-35 digital program insertion cue markers are enabled for ad break signaling within this daypart. When True, Ericsson MediaFirst playout automation inserts SCTE-35 splice_insert commands at ad pod boundaries, enabling Dynamic Ad Insertion (DAI) for OTT and streaming distribution via Akamai CDN.',
    `simulcast_eligible` BOOLEAN COMMENT 'Indicates whether content scheduled in this daypart is eligible for simultaneous multi-platform broadcast (simulcast) across linear, OTT, and digital channels. When True, Ericsson MediaFirst can trigger simulcast distribution workflows for this dayparts programming.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `start_time` TIMESTAMP COMMENT 'The clock time (HH:mm:ss, 24-hour format) at which the daypart begins each applicable day. Used by Ericsson MediaFirst for automated playout boundary detection and by Wide Orbit for ad scheduling slot assignment. Stored as STRING to support broadcast day conventions (e.g., 25:00:00 for post-midnight).',
    `sweeps_period_flag` BOOLEAN COMMENT 'Indicates whether this daypart definition has special audience measurement and programming rules applied during Nielsen sweeps periods (intensive ratings measurement periods in February, May, July, and November). When True, enhanced content scheduling and ad pricing rules may apply.',
    `target_demographic` STRING COMMENT 'Primary audience demographic profile associated with this daypart, expressed using Nielsen standard demographic notation (e.g., A18-49, W25-54, M18-34, HH, P2+). Drives audience targeting in ad sales proposals, GRP/TRP calculations, and content scheduling decisions. Sourced from Nielsen Media Research Platform audience measurement data.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this daypart record. Used for change data capture (CDC), incremental ETL processing in the Databricks Lakehouse Silver layer, and audit trail compliance.',
    `upfront_eligible` BOOLEAN COMMENT 'Indicates whether ad inventory within this daypart is offered during the upfront advance advertising sales event. Prime Time and key dayparts are typically upfront-eligible. Drives Salesforce Media Cloud opportunity and proposal configuration for annual upfront sales cycles.',
    CONSTRAINT pk_daypart PRIMARY KEY(`daypart_id`)
) COMMENT 'Reference definition of named broadcast time segments (e.g., Early Morning, Morning Drive, Daytime, Prime Time, Late Fringe, Overnight) used to govern ad pricing, content scheduling, and audience targeting. Captures daypart code, start/end time boundaries, day-of-week applicability, audience demographic profile, and rate multiplier. Aligns with Nielsen daypart taxonomy and Wide Orbit traffic system. Supports workload modes: Linear|VOD.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`program_schedule` (
    `program_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for the program schedule record. One record per channel per broadcast date per schedule version. This is the primary key of the program_schedule data product.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel for which this schedule is defined. Identifies the linear channel in the channel master (e.g., NBC East, CNN HD). Drives Ericsson MediaFirst playout automation for the specific channel.',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Program schedules are prepared and transmitted via a specific delivery channel (cable, satellite, FAST, OTT). Distribution compliance reporting, affidavit generation, and as-run reconciliation require',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: Program schedule approval requires confirming rights clearance against a governing license agreement. Schedulers and compliance teams use this link to validate run limits, territory restrictions, and ',
    `ad_pod_count` STRING COMMENT 'Total number of ad pods (groups of ads in a break) planned in the schedule for this channel day. An ad pod is a contiguous block of commercial spots within a program break. Used for inventory planning and SCTE-35 cue marker validation.',
    `approved_by` STRING COMMENT 'Name or user identifier of the programming operations staff member who approved this schedule version. Required for audit trail and accountability in the schedule approval workflow. Populated when schedule_status transitions to approved.',
    `approved_timestamp` TIMESTAMP COMMENT 'Timestamp when this schedule version was formally approved by the programming team. Marks the transition from draft to approved status. Used for SLA tracking of schedule readiness lead time before broadcast date.',
    `as_run_confirmed_timestamp` TIMESTAMP COMMENT 'Timestamp when the as-run log was confirmed and reconciled against the planned schedule. Marks the transition to as-run status. Used for Wide Orbit affidavit generation, Nielsen ratings reconciliation, and revenue assurance.',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether any geographic broadcast blackout restriction applies to this schedule. True = one or more programs in this schedule are subject to blackout in specific markets (e.g., sports rights blackout). Triggers downstream blackout enforcement in distribution and CDN systems.',
    `broadcast_date` DATE COMMENT 'The calendar date for which this program schedule is planned and transmitted. Represents the broadcast day (which may span midnight for overnight programming). Formatted as yyyy-MM-dd per enterprise date convention.',
    `content_rating_advisory` STRING COMMENT 'The highest content rating advisory applicable to any program in this schedule for the broadcast day. Used for parental control systems, V-chip compliance, and FCC content standards reporting. Ratings follow the TV Parental Guidelines system mandated by the FCC.. Valid values are `TV-Y|TV-Y7|TV-G|TV-PG|TV-14|TV-MA`',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this program schedule record was first created in the system. Represents the business event time of schedule initiation. Used for audit trail, SLA measurement of schedule build lead time, and data lineage tracking.',
    `emergency_alert_ready` BOOLEAN COMMENT 'Indicates whether the schedule has been configured with Emergency Alert System (EAS) interrupt capability for this broadcast date. True = EAS interrupt slots are provisioned in the Ericsson MediaFirst rundown. Required for FCC EAS compliance.',
    `fcc_children_programming_compliant` BOOLEAN COMMENT 'Indicates whether this schedule meets FCC childrens educational and informational (E/I) programming requirements for the broadcast date. True = minimum required hours of qualifying childrens programming are scheduled. Required for FCC license renewal compliance reporting.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this program schedule record. Tracks the last update across any field change, version increment, or status transition. Used for change detection in downstream EPG distribution and playout systems.',
    `must_carry_compliant` BOOLEAN COMMENT 'Indicates whether this schedule satisfies must-carry obligations for the channel on this broadcast date. Must-carry is the mandatory channel inclusion requirement imposed on cable and satellite MVPDs by the FCC. True = compliant; False = compliance issue requiring resolution.',
    `playout_failover_mode` STRING COMMENT 'Indicates the Ericsson MediaFirst playout failover configuration active for this schedule. primary = normal automated playout; backup = failover to backup playout server; manual_override = operator has taken manual control of playout. Used for SLA and incident reporting.. Valid values are `primary|backup|manual_override`',
    `schedule_end_time` TIMESTAMP COMMENT 'The planned end timestamp of the broadcast schedule for this channel day, including timezone offset. Typically 23:59:59 local broadcast time but may extend past midnight for overnight programming blocks. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `schedule_name` STRING COMMENT 'Human-readable label for the schedule, typically combining channel name and broadcast date (e.g., CNN-HD 2024-06-15 v2). Used by scheduling operations staff to identify and reference the schedule in Ericsson MediaFirst and Wide Orbit Traffic systems.',
    `schedule_notes` STRING COMMENT 'Free-text operational notes entered by scheduling staff regarding special instructions, exceptions, or context for this schedule (e.g., Breaking news override applied to 8PM slot, Live sports event extends prime block by 30 min). Not used for automated processing.',
    `schedule_source` STRING COMMENT 'Indicates how this schedule was generated. manual = built by scheduling staff; automated = generated by Ericsson MediaFirst automated schedule engine; imported = ingested from an external programming supplier or network feed; template = derived from a recurring schedule template.. Valid values are `manual|automated|imported|template`',
    `schedule_start_time` TIMESTAMP COMMENT 'The planned start timestamp of the broadcast schedule for this channel day, including timezone offset. Typically 00:00:00 local broadcast time but may differ for overnight schedules that begin at a non-midnight boundary. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `schedule_version` STRING COMMENT 'Monotonically incrementing version number for the schedule on a given channel and broadcast date. Enables tracking of schedule revisions from initial draft through final as-run. Version 1 is the initial draft; each approved revision increments the version.',
    `scte35_cue_count` STRING COMMENT 'Total number of SCTE-35 digital program insertion cue markers embedded in the schedule for this channel day. SCTE-35 cues signal ad break opportunities for Dynamic Ad Insertion (DAI) in both linear and OTT streams. Used to validate DAI readiness.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this schedule is configured for simultaneous multi-platform broadcast (simulcast). True = the schedule is transmitted concurrently across linear broadcast and one or more OTT/streaming platforms. Drives Ericsson MediaFirst simulcast automation configuration.',
    `simulcast_platform_count` STRING COMMENT 'Number of platforms on which this schedule is simultaneously broadcast when simulcast_flag is True. Used for multi-platform distribution planning and rights compliance verification across linear, OTT, and vMVPD delivery channels.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `timezone` STRING COMMENT 'IANA timezone identifier for the broadcast timezone in which this schedules times are expressed (e.g., America/New_York, Europe/London). Critical for accurate EPG display, daypart classification, and regulatory compliance reporting across markets.',
    `total_ad_time_seconds` STRING COMMENT 'Total planned advertising airtime in seconds across all ad pods in the schedule for this channel day. Used for commercial inventory management, FCC commercial limits compliance, and revenue forecasting against Wide Orbit traffic orders.',
    `total_program_time_seconds` STRING COMMENT 'Total planned programming (non-commercial) airtime in seconds for this channel day schedule. Equals total_runtime_seconds minus total_ad_time_seconds. Used for content utilization reporting and rights compliance verification.',
    `total_runtime_seconds` STRING COMMENT 'Total planned runtime of all program items in the schedule, expressed in seconds. Used to validate that the schedule fills the full broadcast day (86,400 seconds for a 24-hour schedule) and to detect gaps or overlaps in the rundown.',
    `transmission_type` STRING COMMENT '',
    `transmitted_timestamp` TIMESTAMP COMMENT 'Timestamp when the approved schedule was transmitted to the Ericsson MediaFirst playout automation system. Marks the transition from approved to transmitted status. Used for playout readiness SLA monitoring and failover preparation.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    CONSTRAINT pk_program_schedule PRIMARY KEY(`program_schedule_id`)
) COMMENT 'The authoritative linear channel grid (EPG backbone) representing the planned broadcast schedule for a channel on a given broadcast date. Captures schedule version, channel, broadcast date, schedule status (draft, approved, transmitted, as-run), total runtime, blackout flags, must-carry compliance status, and the Ericsson MediaFirst automation rundown reference. One record per channel per broadcast day per schedule version. [DEMO-FITNESS] MVM demo-fitness: Churn prediction & win-back (D2C SVOD) [rating=5/5, status=done]; Rights availability & windowing [rating=5/5, status=best-in-class]; Linear playout + as-run reconciliation [rating=5/5, status=complete]; Production cost & budget vs. actuals [rating=4/5, status=strong]; Compliance / regulatory reporting [rating=5/5, status=complete]; Overall bottom-line [rating=n/a/5, status=substantially above average] Supports workload modes: Linear|FAST.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`schedule_slot` (
    `schedule_slot_id` BIGINT COMMENT 'Unique surrogate identifier for each individual schedule slot record within the Electronic Program Guide (EPG) rundown. Primary key for the schedule_slot data product managed in Ericsson MediaFirst.',
    `ad_pod_id` BIGINT COMMENT 'Reference to the ad pod (group of commercials within a break) associated with this slot when the slot type is a commercial break. Populated only for commercial break slots; null for program and promo slots.',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: Traffic and scheduling systems perform pre-transmission asset readiness checks by confirming a specific QC-approved asset version is assigned to each slot. This version-level slot assignment is a name',
    `channel_id` BIGINT COMMENT 'Reference to the linear broadcast channel on which this schedule slot is programmed. Identifies the originating channel within the EPG grid.',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: Schedule slots must specify which content version (resolution, language, DRM profile) is scheduled for broadcast. Traffic and playout systems require version-level FK for rights window validation, tec',
    `content_window_id` BIGINT COMMENT 'Foreign key linking to rights.rights_content_window. Business justification: Rights content windows define the exact date/time window during which content may be broadcast. Scheduling must validate each slot against the active rights window to prevent out-of-window airings — a',
    `daypart_id` BIGINT COMMENT 'Reference to the daypart classification assigned to this slot (e.g., Prime Time, Late Night, Morning Drive). Dayparts are standard time segments of the broadcast day used for audience targeting and advertising rate-card pricing.',
    `episode_id` BIGINT COMMENT 'Foreign key linking to content.content_episode. Business justification: schedule_slot carries denormalized episode_number. Linking to content_episode enables episode-level rerun tracking (runs_consumed vs runs_allowed), FCC childrens programming compliance reporting, and',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: Each schedule slot places content on air under a specific license agreement governing run counts, territory, and blackout rules. Traffic systems must validate slots against the license agreement to pr',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: Schedule slots must reference the specific media file for playout automation systems (MediaFirst, WideOrbit) to execute. Critical for broadcast operations - automation pulls the actual file URI from t',
    `profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: On-air talent (hosts, anchors, guests) are scheduled in broadcast slots. Scheduling systems track which talent appears in which slot for call sheets, union reporting, rights clearance verification, an',
    `program_schedule_id` BIGINT COMMENT 'Reference to the parent broadcast schedule or rundown document that contains this slot. Links the atomic slot to its daily or weekly schedule container in Ericsson MediaFirst.',
    `role_id` BIGINT COMMENT 'Foreign key linking to talent.role. Business justification: Residual payment calculations and EPG credit display require knowing WHICH role a talent performs in each slot (character name, billing position, residual_rate_code), not just who the talent is. SAG-A',
    `title_id` BIGINT COMMENT 'Reference to the content asset or media item assigned to this slot. Links to the Digital Asset Management (DAM) record in Dalet Galaxy for the program, promo, commercial, or filler material.',
    `actual_duration_seconds` STRING COMMENT 'Real-world duration of the slot in seconds as recorded in the as-run log. Compared against planned_duration_seconds to identify overruns, underruns, and schedule compliance deviations. Used in affidavit reconciliation and makegoods processing.',
    `actual_start_time` TIMESTAMP COMMENT 'Real-world start time of the slot as recorded in the as-run log by Ericsson MediaFirst playout automation. May differ from planned_start_time due to live events, technical delays, or schedule overruns. Critical for affidavit generation in Wide Orbit and Nielsen audience measurement reconciliation.',
    `aspect_ratio` DECIMAL(18,2) COMMENT 'Video aspect ratio of the content assigned to this slot. Drives playout automation letterboxing/pillarboxing decisions in Ericsson MediaFirst and ensures compliance with broadcast technical standards.',
    `broadcast_date` DATE COMMENT 'Calendar date on which this slot is scheduled to air, expressed in yyyy-MM-dd format. Used as the primary partition key for EPG queries, Nielsen ratings alignment, and daily schedule reporting. Represents the broadcast day which may span midnight for overnight programming.',
    `closed_caption_flag` BOOLEAN COMMENT 'Indicates whether closed captioning is present and enabled for this slot (True). Mandatory for FCC compliance under the Twenty-First Century Communications and Video Accessibility Act (CVAA) for applicable programming.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this schedule slot record was first created in the EPG system. Supports audit trail requirements, schedule change history analysis, and data lineage tracking in the Databricks Silver Layer.',
    `is_blackout` BOOLEAN COMMENT 'Indicates whether a geographic broadcast restriction (blackout) applies to this slot (True). Blackout rules are enforced at the distribution layer and must be flagged at the slot level for rights compliance and audience measurement exclusion.',
    `is_live` BOOLEAN COMMENT 'Indicates whether this slot carries a live broadcast event (True) or pre-recorded/taped content (False). Live slots require different playout automation handling, DAI configuration, and rights clearance verification in Rightsline.',
    `is_repeat` BOOLEAN COMMENT 'Indicates whether this slot is a repeat airing of previously broadcast content (True) rather than a first-run premiere (False). Affects talent residuals calculations in Rightsline and Nielsen audience measurement weighting.',
    `is_simulcast` BOOLEAN COMMENT 'Indicates whether this slot is simultaneously broadcast across multiple platforms or channels (True). Simulcast slots require coordinated playout across linear and OTT/streaming distribution paths and may trigger additional rights obligations.',
    `must_carry_flag` BOOLEAN COMMENT 'Indicates whether this slot is subject to must-carry obligations requiring MVPDs to include this channel/content in their basic tier (True). Flags slots that cannot be blacked out or substituted under FCC must-carry rules.',
    `planned_duration_seconds` STRING COMMENT 'Intended duration of the slot in seconds as scheduled in the EPG rundown. Used for schedule integrity validation, ad pod capacity planning, and compliance with broadcast standards for minimum program duration.',
    `planned_end_time` TIMESTAMP COMMENT 'Scheduled end date and time for this slot as defined in the EPG rundown. Derived from planned_start_time plus planned_duration_seconds but stored explicitly to support EPG grid queries and boundary validation.',
    `planned_start_time` TIMESTAMP COMMENT 'Scheduled start date and time for this slot as defined in the EPG rundown prior to broadcast. Expressed in ISO 8601 format with timezone offset. Used for EPG publication, audience measurement alignment, and ad trafficking in Wide Orbit.',
    `program_title` STRING COMMENT 'Human-readable title of the program or content event airing in this slot as it appears in the published EPG. Used for audience-facing program guides, Nielsen ratings matching, and schedule reporting.',
    `resolution` STRING COMMENT 'Video resolution classification of the content in this slot (SD, HD, UHD, 4K). Determines the playout chain and CDN delivery profile used by Akamai and affects carriage fee agreements with MVPDs.. Valid values are `SD|HD|UHD|4K`',
    `schedule_version` STRING COMMENT 'Version number of the schedule rundown in which this slot was last modified. Incremented each time the EPG rundown is revised in Ericsson MediaFirst. Supports schedule change audit trails and version comparison for compliance reporting.',
    `scte35_cue_in_time` TIMESTAMP COMMENT 'Timestamp of the SCTE-35 splice_insert cue-in signal marking the return to primary program content after an ad break. Paired with scte35_cue_out_time to define the exact ad avail window for DAI and Wide Orbit ad scheduling.',
    `scte35_cue_out_time` TIMESTAMP COMMENT 'Timestamp of the SCTE-35 splice_insert cue-out signal marking the start of an ad break or content interruption within this slot. Used by Dynamic Ad Insertion (DAI) systems and downstream distribution platforms to trigger ad replacement. Null for non-break slot types.',
    `slot_sequence_number` STRING COMMENT 'Ordinal position of this slot within the daily rundown for the channel. Determines the playout order in Ericsson MediaFirst automation. Sequence numbers are contiguous integers starting at 1 for each broadcast day.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `traffic_order_number` STRING COMMENT 'Wide Orbit traffic system order number associated with this slot when it carries a commercial or promotional spot. Links the EPG slot to the ad sales order for affidavit generation, billing reconciliation, and makegood processing.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this schedule slot record was last modified. Tracks EPG edits, schedule revisions, and as-run updates. Used in conjunction with schedule_version for change management and compliance audit.',
    CONSTRAINT pk_schedule_slot PRIMARY KEY(`schedule_slot_id`)
) COMMENT 'Individual time slot within a program schedule representing a single content event or break event on a linear channel. Captures slot sequence number, planned start time, planned duration, actual start time (as-run), actual duration, slot type (program, promo, commercial break, filler, PSA, EAS), content reference, daypart assignment, and live/tape flag. The atomic unit of the EPG rundown managed in Ericsson MediaFirst. Supports workload modes: Linear|FAST|VOD.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`epg_entry` (
    `epg_entry_id` BIGINT COMMENT 'Unique surrogate identifier for each Electronic Program Guide (EPG) entry record in the scheduling domain. Serves as the primary key for this Silver Layer data product.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel on which this EPG entry is scheduled for playout. Links to the channel master record in the scheduling domain.',
    `content_window_id` BIGINT COMMENT 'Foreign key linking to rights.rights_content_window. Business justification: EPG entries carry denormalized rights_window_start/rights_window_end columns derived from rights_content_window. Replacing these with a proper FK enables automated EPG suppression when windows close a',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: EPG entries are published to specific delivery channels (cable guide, OTT platform EPG feed, FAST channel). EPG feed syndication workflows and guide data publishing pipelines require knowing which del',
    `episode_id` BIGINT COMMENT 'Foreign key linking to content.content_episode. Business justification: EPG entries represent specific episode airings; linking to content_episode enables accurate episode-level metadata (episode number, VOD availability dates, music cue sheet status) for EPG feeds and ep',
    `media_asset_id` BIGINT COMMENT 'Reference to the media content asset in the Digital Asset Management system (Dalet Galaxy) that is being broadcast for this EPG entry.',
    `schedule_slot_id` BIGINT COMMENT 'Reference to the approved schedule slot from which this EPG entry was derived. Represents the authoritative playout scheduling record in Ericsson MediaFirst.',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: EPG entries require daypart linkage for audience reach estimation, program discovery optimization, and daypart-based content recommendations. Creates new scheduling_daypart_id FK (role-prefixed to avo',
    `series_id` BIGINT COMMENT 'Foreign key linking to content.series. Business justification: epg_entry carries denormalized series_name. Linking to content.series normalizes series metadata for EPG series grouping, catch-up TV features, and series-level audience reporting. Broadcasting EPG sy',
    `title_id` BIGINT COMMENT 'Foreign key linking to content.title. Business justification: EPG publishing requires linking each EPG entry to the canonical content.title record to pull authoritative metadata (synopsis, rating, ISAN) for guide feeds. A broadcasting EPG operator would consider',
    `ad_pod_count` STRING COMMENT 'The number of ad pods (groups of advertisements within a break) scheduled within this program. Used for advertising inventory planning, Wide Orbit traffic scheduling, and revenue forecasting.',
    `blackout_region_codes` STRING COMMENT 'Comma-separated list of geographic region or market codes where this program is subject to broadcast blackout restrictions. Used by distribution systems to suppress EPG entry delivery in restricted markets. Populated only when is_blackout is True.',
    `broadcast_date` DATE COMMENT 'The calendar date on which this program is scheduled to air, in yyyy-MM-dd format. Used for day-level EPG grid display, daypart assignment, and schedule reporting.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `distribution_window` STRING COMMENT 'The distribution window or release strategy under which this EPG entry is being broadcast, reflecting the windowing strategy for sequential content release. Determines rights availability and platform eligibility per Rightsline contract terms.. Valid values are `linear|svod|avod|tvod|fast|syndication`',
    `duration_seconds` STRING COMMENT 'The total scheduled duration of the program in seconds, derived from the difference between scheduled start and end times. Used for EPG display, ad pod planning, and playout automation validation.',
    `eidr` STRING COMMENT 'The Entertainment Identifier Registry (EIDR) identifier for this content, providing a universal content identifier used across the media supply chain for content tracking, rights management, and EPG data exchange with MVPDs and vMVPDs.. Valid values are `^10.5240/[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}$`',
    `epg_feed_version` STRING COMMENT 'The version number of this EPG entry record as distributed in the EPG feed. Incremented each time the entry is updated and redistributed to MVPDs, vMVPDs, and digital platforms. Enables downstream systems to detect and apply updates.',
    `episode_title` STRING COMMENT 'The title of the specific episode within a series, as displayed in the EPG. Null for non-episodic content such as feature films or standalone specials.',
    `genre_primary` STRING COMMENT 'The primary content genre classification for this EPG entry as distributed in the EPG feed (e.g., Drama, Comedy, News, Sports, Documentary, Reality). Used for viewer discovery, content filtering, and audience analytics. [ENUM-REF-CANDIDATE: drama|comedy|news|sports|documentary|reality|entertainment|children|film|music — promote to reference product]',
    `genre_secondary` STRING COMMENT 'An optional secondary genre sub-classification providing more granular content categorization for EPG discovery and audience targeting (e.g., Crime Drama, Political Comedy, Investigative Documentary).',
    `is_blackout` BOOLEAN COMMENT 'Indicates whether geographic broadcast restrictions (blackout) apply to this EPG entry (True). When True, the program is subject to blackout rules that restrict distribution in specific geographic markets per rights agreements managed in Rightsline.',
    `is_closed_caption` BOOLEAN COMMENT 'Indicates whether closed captioning (CC) is available for this program (True). Distributed in EPG feeds for accessibility compliance and viewer information. Required for FCC closed captioning regulatory compliance.',
    `is_hdr` BOOLEAN COMMENT 'Indicates whether this program is available in High Dynamic Range (HDR) format (True). Distributed in EPG feeds to inform viewers and set-top boxes of enhanced picture quality availability.',
    `is_live` BOOLEAN COMMENT 'Indicates whether this EPG entry represents a live broadcast event (True) as opposed to a pre-recorded or time-shifted program (False). Drives playout automation configuration in Ericsson MediaFirst and is distributed in EPG feeds for viewer-facing live indicators.',
    `is_new_episode` BOOLEAN COMMENT 'Indicates whether this EPG entry represents a new, first-run episode (True) or a repeat/rerun broadcast (False). Distributed in EPG feeds for viewer-facing NEW indicators and drives audience measurement prioritization.',
    `is_simulcast` BOOLEAN COMMENT 'Indicates whether this program is being simultaneously broadcast across multiple platforms or channels (simulcast). When True, the same content is distributed concurrently on linear and digital/OTT platforms.',
    `isan` STRING COMMENT 'The International Standard Audiovisual Number (ISAN) uniquely identifying this audiovisual work globally. Used for rights management, content identification across platforms, and interoperability with Rightsline and international content registries.. Valid values are `^[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}-[0-9A-F]{4}-[0-9A-F]{4}-[0-9A-F]{1}$`',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this EPG entry record was most recently modified, including schedule changes, metadata updates, or status transitions. Used for change detection in downstream EPG feed distribution and audit trail.',
    `program_title` STRING COMMENT 'The primary viewer-facing title of the program as it appears in the Electronic Program Guide. Used for consumer-facing program discovery across all distribution platforms.',
    `published_timestamp` TIMESTAMP COMMENT 'The date and time when this EPG entry was first published and distributed to external EPG feeds (MVPDs, vMVPDs, set-top boxes, digital platforms). Serves as the record audit created timestamp for this data product.',
    `scheduled_end_time` TIMESTAMP COMMENT 'The precise date and time at which this program is scheduled to end broadcast on the channel. Used to calculate program duration and to sequence adjacent EPG entries in the linear channel grid.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The precise date and time at which this program is scheduled to begin broadcast on the channel, expressed in ISO 8601 format with timezone offset. This is the principal business event timestamp for the EPG entry and drives all downstream playout automation in Ericsson MediaFirst.',
    `scte35_cue_out_time` TIMESTAMP COMMENT 'The timestamp of the SCTE-35 splice_insert cue-out signal marking the start of an ad break opportunity within this program. Used by Dynamic Ad Insertion (DAI) systems and Wide Orbit traffic systems for ad pod placement and automated ad scheduling.',
    `season_number` STRING COMMENT 'The season number within the series for this episode. Used for EPG display and content navigation. Null for non-episodic or non-seasonal content.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `synopsis_long` STRING COMMENT 'A detailed program description (typically up to 500 characters) distributed in EPG feeds for display on digital platforms, OTT apps, and web-based program guides. Sourced from Dalet Galaxy content metadata.',
    `synopsis_short` STRING COMMENT 'A brief program description (typically up to 100 characters) distributed in EPG feeds for display on set-top boxes and digital platforms with limited screen real estate. Sourced from Dalet Galaxy content metadata.',
    `total_ad_break_duration_seconds` STRING COMMENT 'The total cumulative duration in seconds of all scheduled ad breaks within this program. Used for advertising inventory management, compliance with ad load regulations, and Wide Orbit traffic scheduling.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `video_resolution` STRING COMMENT 'The video resolution format of this program as distributed in the EPG feed (e.g., SD, HD, FHD, UHD/4K). Used for viewer-facing display in EPG interfaces and for platform compatibility routing.. Valid values are `SD|HD|FHD|UHD|4K|8K`',
    CONSTRAINT pk_epg_entry PRIMARY KEY(`epg_entry_id`)
) COMMENT 'Published Electronic Program Guide record distributed to MVPDs, vMVPDs, set-top boxes, and digital platforms for viewer-facing program discovery. Captures program title, episode title, series name, genre, content rating (MPA), short and long synopsis, start/end time, channel, language, closed-caption flag, HDR/resolution flag, ISAN/EIDR identifier, and distribution window. Derived from approved schedule slots and enriched with content metadata for consumer-facing EPG feeds. Supports workload modes: Linear|OTT|FAST.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`ad_break` (
    `ad_break_id` BIGINT COMMENT 'Unique surrogate identifier for the ad break (ad pod) record within the scheduling domain. Primary key for this entity.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel on which this ad break is scheduled for playout. Supports multi-channel scheduling and channel-level inventory reporting.',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: Ad break currently stores daypart_code as a STRING. This should be normalized to FK to the daypart reference table. Ad break pricing, GRP targets, and inventory management all depend on daypart attrib',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Ad breaks are managed per delivery channel — linear cable breaks differ from OTT DAI breaks in avail count, pricing, and insertion method. Ad trafficking, avail reporting, and DAI configuration workfl',
    `scte_marker_id` BIGINT COMMENT 'The identifier of the SCTE-35 splice_insert or time_signal cue-out marker that signals the start of the ad break to downstream distribution systems and Dynamic Ad Insertion (DAI) platforms. References the specific SCTE-35 message that triggers break entry.',
    `schedule_slot_id` BIGINT COMMENT 'Reference to the parent schedule slot within which this ad break is positioned. Links the ad break to its containing program or interstitial window in the linear channel grid.',
    `actual_duration_seconds` STRING COMMENT 'The actual total duration of the ad break as recorded during playout by the Ericsson MediaFirst automation system. Used for post-log reconciliation, affidavit generation, and makegood assessment when actual duration deviates from planned.',
    `actual_start_time` TIMESTAMP COMMENT 'The actual wall-clock time at which the ad break commenced during playout, as recorded by the Ericsson MediaFirst automation system. Used for affidavit generation and post-log reconciliation against the scheduled start time.',
    `affidavit_generated` BOOLEAN COMMENT 'Indicates whether a proof-of-broadcast affidavit has been generated for this ad break in the Wide Orbit traffic system following confirmed playout. Affidavits are required for advertiser billing reconciliation and regulatory compliance.',
    `avail_count` STRING COMMENT 'The total number of individual advertising avail slots (unit positions) within this ad break pod. Each avail represents a discrete sellable unit (e.g., a 30-second spot position). Used for inventory capacity planning and traffic scheduling.',
    `blackout_restricted` BOOLEAN COMMENT 'Indicates whether this ad break is subject to geographic blackout restrictions that prevent its broadcast or streaming in specific markets or regions. When true, downstream distribution systems must apply blackout logic per rights and regulatory obligations.',
    `break_position` STRING COMMENT 'Positional classification of the ad break relative to the surrounding program content. pre-roll = before program content begins; mid-roll = within program content; post-roll = after program content ends; interstitial = between programs in the schedule grid.. Valid values are `pre-roll|mid-roll|post-roll|interstitial`',
    `break_type` STRING COMMENT '',
    `broadcast_date` DATE COMMENT 'The calendar date on which this ad break is scheduled to air, expressed in the channels broadcast day convention (which may differ from the wall-clock date for late-night programming). Used for daily traffic scheduling, affidavit generation, and revenue reporting.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this ad break record was first created in the scheduling system. Serves as the RECORD_AUDIT_CREATED field for data lineage, audit trail, and Silver layer ingestion tracking.',
    `dai_eligible` BOOLEAN COMMENT 'Indicates whether this ad break is enabled for Dynamic Ad Insertion (DAI), allowing server-side ad replacement for OTT/streaming simulcast audiences. When true, the break is eligible for addressable advertising via DAI platforms such as those integrated with Akamai CDN.',
    `epg_break_label` STRING COMMENT 'The human-readable label or descriptor for this ad break as it appears in the Electronic Program Guide (EPG) and scheduling rundown. Used by traffic coordinators and scheduling operators to identify breaks in the EPG interface.',
    `grp_target` DECIMAL(18,2) COMMENT 'The target Gross Rating Point (GRP) value for this ad break, representing the expected total audience delivery as a percentage of the total target population. Used for audience guarantee tracking and campaign delivery reporting against Nielsen ratings.',
    `makegood_required` BOOLEAN COMMENT 'Indicates whether a makegood (compensatory ad spot) is required for this break due to a failure to air as contracted — for example, due to preemption, technical failure, or underdelivery. Triggers makegood workflow in Wide Orbit.',
    `max_duration_seconds` STRING COMMENT 'The maximum allowable duration of the ad break in seconds, representing the hard ceiling for total ad content that may be inserted. Exceeding this value would cause schedule overrun. May differ from planned duration when flex time is permitted.',
    `nielsen_program_rating` DECIMAL(18,2) COMMENT 'The Nielsen audience rating for the program surrounding this ad break, representing the percentage of total TV households tuned in. Used for CPM calculation, audience guarantee assessment, and scatter market pricing.',
    `planned_duration_seconds` STRING COMMENT 'The planned total duration of the ad break (ad pod) in seconds as defined in the program schedule. Represents the total sellable commercial time allocated to this break. Standard pod durations are typically 30, 60, 90, 120, or 180 seconds.',
    `pod_number` STRING COMMENT 'The pod number identifying this ad break within the broadcast day for the channel. Distinct from sequence_number (which is relative to the program); pod_number is the channel-day-level ordinal used in traffic scheduling and affidavit reporting.',
    `preemption_reason` STRING COMMENT 'The reason code explaining why this ad break was preempted or cancelled if it did not air as scheduled. Used for makegood processing, revenue assurance, and operational reporting. none when the break aired as planned.. Valid values are `breaking_news|emergency_alert|technical_failure|rights_conflict|schedule_change|none`',
    `rate_card_cpm` DECIMAL(18,2) COMMENT 'The published rate card CPM (Cost Per Mille — cost per 1,000 audience impressions) for this ad break, expressed in the local currency. Represents the base pricing for inventory in this break before negotiated discounts. Used for revenue forecasting and yield management.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The planned wall-clock date and time at which the ad break is scheduled to begin on the linear channel. Expressed in the channels broadcast timezone. This is the principal BUSINESS_EVENT_TIMESTAMP for the break.',
    `sequence_number` STRING COMMENT 'Ordinal position of this ad break within the parent schedule slot or program. Used to order multiple breaks within a single program (e.g., break 1, break 2, break 3) for traffic scheduling and playout automation.',
    `simulcast_eligible` BOOLEAN COMMENT 'Indicates whether this ad break is included in the simultaneous multi-platform broadcast (simulcast) of the channel. When false, the break may be suppressed or replaced on simulcast streams (e.g., OTT, vMVPD).',
    `sold_avail_count` STRING COMMENT 'The number of individual avail slots within this break that have been sold and assigned to advertiser spots in the Wide Orbit traffic system. Used with avail_count to compute sellout rate and unsold inventory.',
    `sold_duration_seconds` STRING COMMENT 'The total duration in seconds of ad inventory within this break that has been sold to advertisers via the Wide Orbit traffic system. Used to calculate unsold (remnant) inventory and sellout rate for revenue assurance reporting.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this ad break record was most recently modified in the scheduling system. Serves as the RECORD_AUDIT_UPDATED field for change tracking, incremental data pipeline processing, and audit compliance.',
    CONSTRAINT pk_ad_break PRIMARY KEY(`ad_break_id`)
) COMMENT 'Commercial break (ad pod) within a schedule slot — capturing break position (pre-roll, mid-roll, post-roll), sequence number, planned and maximum pod duration, break type (local avail, network avail, promotional), SCTE-35 cue-in/cue-out marker references, DAI eligibility flag, and Wide Orbit traffic system break ID. The structural container for sellable ad inventory within the linear schedule, linking scheduling to advertising sales fulfillment. Supports workload modes: Linear|FAST|DAI.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`scte_marker` (
    `scte_marker_id` BIGINT COMMENT 'Unique surrogate identifier for each SCTE-35 splice information message record in the broadcast transport stream. Primary key for the scte_marker data product.',
    `ad_pod_id` BIGINT COMMENT 'Reference to the ad pod record that this SCTE-35 marker is intended to open or close. An Ad Pod is a group of ads scheduled within a single break. Links the splice event to the Wide Orbit traffic system ad pod for campaign reconciliation and affidavit generation.',
    `channel_id` BIGINT COMMENT 'Reference to the linear broadcast channel on which this SCTE-35 marker was embedded. Links the splice event to the originating playout channel managed in Ericsson MediaFirst.',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: SCTE marker currently stores daypart_code as a STRING. Normalizing to FK enables retrieval of daypart attributes for ad insertion rules and DAI eligibility checks. Remove daypart_code as it becomes re',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: SCTE-35 markers are delivery-channel-specific signals — a marker on a cable feed differs from one on an OTT stream in routing and DAI behavior. Ad insertion systems and DAI platforms require this link',
    `program_schedule_id` BIGINT COMMENT 'Reference to the program schedule entry or rundown record that triggered this SCTE-35 marker. Ties the splice event to the Electronic Program Guide (EPG) scheduling context.',
    `schedule_slot_id` BIGINT COMMENT 'Foreign key linking to scheduling.schedule_slot. Business justification: SCTE-35 markers signal ad insertion points at specific schedule slots. Currently scte_marker links to program_schedule (schedule_id) but not to the specific schedule_slot where the cue is embedded. Ad',
    `title_id` BIGINT COMMENT 'Reference to the program or content asset record associated with this splice event. Links the SCTE-35 marker to the content catalogue in Dalet Galaxy for rights verification, blackout enforcement, and audience measurement attribution.',
    `auto_return` BOOLEAN COMMENT 'Indicates whether the playout system should automatically return to network programming at the end of the break_duration without waiting for an explicit splice-in command. When True, the break is time-bounded; when False, an explicit splice-in SCTE-35 message is required.',
    `avail_num` STRING COMMENT 'The avail_num field from the SCTE-35 splice_insert() command, indicating the sequential number of this ad avail within the current program. Used alongside avails_expected to track avail inventory completeness for a given program break sequence.',
    `avails_expected` STRING COMMENT 'The avails_expected field from the SCTE-35 splice_insert() command, indicating the total number of ad avails expected within the current program. Enables DAI systems and Wide Orbit to validate that all avail windows have been signalled and filled.',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether this SCTE-35 marker is associated with a geographic broadcast blackout restriction. When True, downstream MVPDs and vMVPDs must suppress the content in the affected geographic region and substitute alternate programming or a blackout slate.',
    `break_duration_ms` STRING COMMENT 'The total duration of the ad break or content replacement window in milliseconds, as signalled in the SCTE-35 break_duration() structure. Defines the length of the avail window available for ad pod insertion. Used by Wide Orbit traffic system for avail reconciliation.',
    `component_count` STRING COMMENT 'Number of elementary stream components (video, audio tracks, data) included in the splice command when component_splice_flag is set. Indicates multi-component splice operations for multi-language or multi-audio broadcast streams.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'UTC timestamp when this SCTE-35 marker record was first created in the Silver layer data product. Audit trail field for data lineage and pipeline monitoring.',
    `cw_index` STRING COMMENT 'The cw_index field from the SCTE-35 splice_info_section, referencing the encryption control word used when the splice message is encrypted. A value of 0xFF indicates no encryption. Relevant for DRM-protected transport streams.',
    `descriptor_loop_length` STRING COMMENT 'The total byte length of the splice descriptor loop in the SCTE-35 splice_info_section. Indicates the presence and size of additional descriptors such as segmentation_descriptor, DTMF_descriptor, or avail_descriptor. Used for message parsing validation.',
    `encrypted_packet` BOOLEAN COMMENT 'Indicates whether the SCTE-35 splice_info_section payload is encrypted. When True, the cw_index field identifies the applicable decryption key. Relevant for secure ad insertion in DRM-protected broadcast streams.',
    `out_of_network` BOOLEAN COMMENT 'The out_of_network_indicator bit from the SCTE-35 splice_insert() command. True indicates the splice point transitions to out-of-network content (e.g., local ad insertion); False indicates a return to in-network programming. Fundamental for MVPD local ad insertion compliance.',
    `pre_roll_duration_ms` STRING COMMENT 'The pre-roll duration in milliseconds between the time the SCTE-35 message is detected and the actual splice point. Allows downstream DAI systems and MVPDs sufficient lead time to prepare and insert the ad content before the avail window opens.',
    `program_number` STRING COMMENT 'The MPEG-2 program_number (PAT/PMT) identifying the specific program within the transport stream to which this SCTE-35 message applies. Enables precise association of the splice event with the correct elementary stream in multi-programme multiplexes.',
    `pts_time` BIGINT COMMENT 'The 33-bit Presentation Time Stamp (PTS) value in 90 kHz clock ticks at which the splice event is to occur in the MPEG-2 transport stream. Stored as BIGINT to accommodate the full 33-bit range. Fundamental for frame-accurate ad insertion by DAI systems and Akamai CDN delivery.',
    `pts_time_utc` TIMESTAMP COMMENT 'Wall-clock UTC timestamp derived from the PTS value after applying the PCR/PTS offset for the channel. Enables correlation of splice events with EPG schedules, ad trafficking records in Wide Orbit, and audience measurement windows in Nielsen.',
    `segmentation_type_code` STRING COMMENT 'Numeric segmentation_type_id from the SCTE-35 segmentation_descriptor (SCTE-104 descriptor table). Identifies the semantic purpose of the marker: e.g., 0x10 = Program Start, 0x11 = Program End, 0x20 = Chapter Start, 0x30 = Provider Advertisement Start, 0x34 = Distributor Advertisement Start. Critical for MVPD ad insertion compliance and blackout enforcement.',
    `segmentation_type_label` STRING COMMENT 'Human-readable label corresponding to the segmentation_type_id, derived from the SCTE-35 segmentation descriptor table (e.g., Provider Advertisement Start, Program Blackout Override, Chapter Start). Facilitates operational reporting and EPG reconciliation without requiring lookup joins.',
    `segmentation_upid_type` STRING COMMENT 'Numeric code identifying the type of the segmentation UPID carried in the segmentation_descriptor, per SCTE-35 Table 22. Common values: 0x01=URI, 0x03=Ad-ID, 0x08=ISAN, 0x09=TID, 0x0A=TI, 0x0C=MPU, 0x0E=ADS Information. Determines how the segmentation_upid_value should be interpreted.',
    `segmentation_upid_value` DECIMAL(18,2) COMMENT 'The actual UPID value carried in the segmentation_descriptor, interpreted according to segmentation_upid_type. May contain an Ad-ID, ISAN, URI, or other content identifier. Used to link the splice event to content records in Dalet Galaxy MAM and rights records in Rightsline.',
    `signal_detected_timestamp` TIMESTAMP COMMENT 'Wall-clock UTC timestamp at which the SCTE-35 splice_info_section was first detected and extracted from the transport stream by the playout or monitoring system. Represents the business event time of signal receipt. Used for pre-roll lead time calculation and SLA monitoring.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `splice_command_type` STRING COMMENT '',
    `splice_event_number` BIGINT COMMENT 'Unique 32-bit splice_event_id as defined in the SCTE-35 splice_insert() command structure. Identifies the specific splice event within the transport stream and is used by Dynamic Ad Insertion (DAI) systems to correlate splice-in and splice-out pairs.',
    `splice_immediate` BOOLEAN COMMENT 'Indicates whether the splice should occur immediately upon receipt of the SCTE-35 message (True) rather than at the specified PTS time (False). When True, the pts_time field is not applicable. Used for emergency override and live event boundary signalling.',
    `tier` STRING COMMENT 'The 12-bit tier field from the SCTE-35 splice_info_section, used to address specific MVPDs or distribution tiers. A value of 0xFFF indicates the message applies to all tiers. Enables selective ad insertion targeting for specific distribution partners.',
    `transport_stream_number` STRING COMMENT 'The MPEG-2 transport stream identifier in which this SCTE-35 message was embedded. Used to correlate the splice event with the specific multiplex or virtual channel carrying the broadcast signal, particularly relevant for DVB and ATSC multi-programme transport streams.',
    `unique_program_code` STRING COMMENT 'The unique_program_id field from the SCTE-35 splice_insert() command, identifying the program associated with this splice event. Used by MVPDs and DAI systems to associate the avail with a specific program for audience targeting and ad campaign attribution.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'UTC timestamp when this SCTE-35 marker record was last modified in the Silver layer data product, such as when processing_status is updated after DAI system acknowledgement.',
    CONSTRAINT pk_scte_marker PRIMARY KEY(`scte_marker_id`)
) COMMENT 'SCTE-35 splice information message record embedded in the broadcast transport stream to signal ad insertion, blackout, and program boundary events. Captures splice command type (splice_insert, time_signal, bandwidth_reservation), PTS timestamp, pre-roll duration, segmentation type ID (SCTE-104 descriptor), unique program ID, avail number, avails expected, and processing status. Critical for DAI systems and MVPD ad insertion compliance. Supports workload modes: Linear|DAI.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`playout_event` (
    `playout_event_id` BIGINT COMMENT 'Unique surrogate identifier for each as-run playout event record in the Ericsson MediaFirst as-run log. Serves as the primary key for this table.',
    `ad_pod_id` BIGINT COMMENT 'Identifier of the advertising pod (Ad Pod) to which this playout event belongs, if the event is a commercial break or advertisement. Links to the Wide Orbit ad scheduling record for billing reconciliation.',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: As-run logs (affidavit generation) must record the exact asset version actually played out for QC reconciliation and regulatory compliance. The existing media_asset_id link is insufficient — broadcast',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel on which this playout event was transmitted. Links to the channel master record.',
    `clearance_request_id` BIGINT COMMENT 'Foreign key linking to rights.clearance_request. Business justification: At playout time, the system must confirm rights clearance was obtained for the content being broadcast. Linking playout_event to its clearance_request supports as-run affidavit generation and post-bro',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: playout_event records actual transmission; linking to the specific content version played is required for as-run log generation, rights consumption tracking (runs_consumed per version), QC incident re',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: Playout event currently stores daypart_code as a STRING. As-run logs need to reference daypart attributes for affidavit generation, Nielsen reporting, and GRP calculation. Normalizing to FK enables JO',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Playout events represent actual transmission occurrences. As-run logs, affidavit generation, and distribution compliance reporting require knowing which delivery channel each playout event was transmi',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: As-run logs must capture the actual media file played for affidavit generation, FCC compliance reporting, and discrepancy analysis. Playout events record what actually aired at file level, not just ti',
    `title_id` BIGINT COMMENT 'Reference to the content asset (programme, advertisement, interstitial, or filler) that was transmitted in this playout event. Links to the content master in the Digital Asset Management system.',
    `profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: Playout systems log actual talent appearances for affidavit generation, residual payment calculation triggers, and as-run reconciliation against talent contracts. Required for guild reporting, usage r',
    `program_rundown_id` BIGINT COMMENT 'Foreign key linking to scheduling.program_rundown. Business justification: A playout_event is the as-run log record from Ericsson MediaFirst capturing actual transmission. For live and studio programs, the playout_event executes against a program_rundown — the rundown define',
    `program_schedule_id` BIGINT COMMENT 'Reference to the planned program schedule entry from which this playout event was derived. Enables deviation analysis between planned and actual transmission.',
    `schedule_slot_id` BIGINT COMMENT 'Foreign key linking to scheduling.schedule_slot. Business justification: Playout events are as-run logs capturing actual transmission of schedule slots. Currently playout_event links to program_schedule but not to the specific schedule_slot that was transmitted. This FK en',
    `scte_marker_id` BIGINT COMMENT 'SCTE-35 splice cue identifier associated with this playout event, used for Dynamic Ad Insertion (DAI) signaling and ad break demarcation. Populated for commercial and interstitial events where SCTE-35 cue markers are active.',
    `streaming_endpoint_id` BIGINT COMMENT 'Foreign key linking to distribution.streaming_endpoint. Business justification: For OTT/streaming playout events, the specific streaming endpoint used is required for QoS monitoring, CDN cost attribution per event, and incident response. A streaming operations engineer would expe',
    `actual_duration_seconds` STRING COMMENT 'Actual transmitted duration of the playout event in seconds as recorded in the as-run log. Used for rights usage reporting, billing reconciliation, and compliance verification.',
    `actual_end_time` TIMESTAMP COMMENT 'Actual transmission end time as recorded in the Ericsson MediaFirst as-run log. Used with actual_start_time to confirm full transmission and calculate actual duration.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual transmission start time as recorded in the Ericsson MediaFirst as-run log. The authoritative timestamp for affidavit generation, rights usage reporting, and regulatory proof-of-performance.',
    `affidavit_generated` BOOLEAN COMMENT 'Indicates whether a broadcast affidavit (proof-of-performance document) has been generated for this playout event in Wide Orbit. Affidavits are the evidentiary basis for advertiser billing and regulatory compliance.',
    `automation_mode` STRING COMMENT 'Operational mode of the Ericsson MediaFirst playout automation at the time of this event. auto = fully automated playout; manual = operator-controlled; override = scheduled automation overridden by operator; failover = backup/failover system active.. Valid values are `auto|manual|override|failover`',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether this playout event was subject to a geographic broadcast blackout restriction. When true, the event was blacked out in one or more markets per rights or regulatory obligations.',
    `broadcast_date` DATE COMMENT 'Calendar date on which this playout event was transmitted, expressed in the channels local broadcast day (which may differ from UTC date for overnight programming).',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this as-run playout event record was first ingested into the Silver layer from the Ericsson MediaFirst as-run log. Serves as the audit creation timestamp for data lineage.',
    `dai_eligible` BOOLEAN COMMENT 'Indicates whether this playout event was eligible for Dynamic Ad Insertion (DAI) on OTT/streaming platforms. Used for digital advertising reconciliation and DAI revenue attribution.',
    `failover_activated` BOOLEAN COMMENT 'Indicates whether the Ericsson MediaFirst failover/backup playout system was active during this event. When true, the primary playout chain was unavailable and the backup system handled transmission.',
    `must_carry_flag` BOOLEAN COMMENT 'Indicates whether this playout event was subject to must-carry obligations requiring mandatory channel inclusion by MVPDs. Used for regulatory compliance reporting to the FCC.',
    `scheduled_duration_seconds` STRING COMMENT 'Planned duration of the playout event in seconds as defined in the program schedule rundown. Used as the baseline for duration deviation analysis.',
    `scheduled_start_time` TIMESTAMP COMMENT 'Planned transmission start time for this event as defined in the Electronic Program Guide (EPG) and program schedule rundown. Used as the baseline for schedule deviation calculation.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this playout event was simultaneously broadcast across multiple platforms (simulcast). When true, the event was transmitted on additional channels or OTT platforms concurrently.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `start_deviation_seconds` STRING COMMENT 'Difference in seconds between actual_start_time and scheduled_start_time. Positive values indicate late start; negative values indicate early start. Key metric for schedule adherence and SLA reporting.',
    `substitution_reason` STRING COMMENT 'Reason code explaining why the originally scheduled content was substituted with alternate content. Populated only when playout_status is substituted. Used for rights compliance and editorial audit trails.. Valid values are `rights_expired|technical_fault|editorial_decision|emergency_override|blackout|operator_override`',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this playout event record was last modified in the Silver layer, for example following affidavit generation, rights clearance update, or schedule reconciliation.',
    CONSTRAINT pk_playout_event PRIMARY KEY(`playout_event_id`)
) COMMENT 'As-run log record from Ericsson MediaFirst capturing actual transmission of each schedule slot as broadcast. Records actual start/end time, duration, content ID, channel, playout status (aired, skipped, substituted, failed), automation mode (auto, manual, override), operator ID, and deviation from planned schedule in seconds. The authoritative as-run record serving as the evidentiary basis for affidavit generation, rights usage reporting, advertiser billing reconciliation, and regulatory proof-of-performance. [DEMO-FITNESS] MVM demo-fitness: Churn prediction & win-back (D2C SVOD) [rating=5/5, status=done]; Rights availability & windowing [rating=5/5, status=best-in-class]; Linear playout + as-run reconciliation [rating=5/5, status=complete]; Production cost & budget vs. actuals [rating=4/5, status=strong]; Compliance / regulatory reporting [rating=5/5, status=complete]; Overall bottom-line [rating=n/a/5, status=substantially above average] Supports workload modes: Linear|FAST.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`program_rundown` (
    `program_rundown_id` BIGINT COMMENT 'Unique surrogate identifier for the program rundown record in the Databricks Silver Layer. Primary key for this entity.',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: Broadcast rundowns are built against a specific encoded asset version (HD/SD, codec profile). Operations must confirm the exact version is available and QC-cleared before transmission. This pre-transm',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel on which this program rundown is executed. Links to the channel master in the scheduling domain.',
    `clearance_request_id` BIGINT COMMENT 'Foreign key linking to rights.clearance_request. Business justification: A program rundowns rights_clearance_status is driven by a specific clearance_request decision. This link enables schedulers to drill into blocking reasons, track SLA compliance, and confirm clearance',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: A program rundown must reference the specific content version (HD/SD, dubbed/subtitled, broadcast-safe cut) to drive playout automation. Rights compliance and as-run log generation depend on knowing e',
    `daypart_id` BIGINT COMMENT 'Foreign key linking to scheduling.daypart. Business justification: Program rundown currently stores daypart_code as a STRING. This should be normalized to FK to the daypart reference table (scheduling_daypart_id). This enables JOIN to retrieve daypart_name, rate_mult',
    `episode_id` BIGINT COMMENT 'Reference to the episode or content asset in the content domain that this rundown is associated with. Enables linkage to content metadata, rights, and digital asset records.',
    `license_agreement_id` BIGINT COMMENT 'Foreign key linking to rights.license_agreement. Business justification: Program rundowns track rights_clearance_status, which is determined by the governing license agreement. Linking rundowns to the license agreement enables automated clearance validation, run-count enfo',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: Live news/sports rundowns reference specific media assets (pre-produced packages, VTR rolls, B-roll) for playout during live production. Production control systems need direct asset references for ope',
    `profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: Live show rundowns (news, talk shows, morning programs) specify primary talent (anchors, hosts) for production coordination, union notification requirements, and screen time tracking. Essential for ca',
    `program_schedule_id` BIGINT COMMENT 'Reference to the parent program schedule entry (Electronic Program Guide slot) that this rundown fulfills. Aligns with scheduling.program_schedule.',
    `schedule_slot_id` BIGINT COMMENT 'Foreign key linking to scheduling.schedule_slot. Business justification: A program_rundown is the detailed production rundown for a live or studio program that occupies a specific schedule_slot. Each rundown belongs to exactly one schedule slot (the broadcast window it fil',
    `ad_pod_count` STRING COMMENT 'Number of commercial break ad pods (groups of ads) planned within this rundown. Used for Wide Orbit traffic scheduling and SCTE-35 cue marker planning.',
    `approved_by` STRING COMMENT 'Name or identifier of the producer or scheduling manager who approved the final rundown for transmission. Required for production accountability and compliance audit trails.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when the rundown was formally approved for playout. Marks the transition from approved to locked status in the production workflow.',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions apply to this program rundown. When True, blackout rules must be enforced by distribution systems per rights agreements managed in Rightsline.',
    `broadcast_date` DATE COMMENT 'The calendar date on which this program rundown is scheduled for transmission. Used for EPG alignment, scheduling compliance, and as-run reconciliation.',
    `content_rating` STRING COMMENT '',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this rundown record was first created in the system, typically when the production team initiates show preparation in Dalet Galaxy.',
    `dai_eligible` BOOLEAN COMMENT 'Indicates whether this program rundown is eligible for Dynamic Ad Insertion (DAI) on streaming/OTT platforms. Drives ad tech configuration in Akamai CDN and Adobe Experience Platform.',
    `dalet_story_code` STRING COMMENT '',
    `emergency_alert_ready` BOOLEAN COMMENT 'Indicates whether the rundown and playout configuration supports Emergency Alert System (EAS) interruption. Required for FCC broadcast compliance and emergency preparedness.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The date and time when this rundown record was last updated. Tracks the most recent editorial or operational change to the rundown for audit and version control purposes.',
    `live_flag` BOOLEAN COMMENT 'Indicates whether the program is transmitted live (True) or is a pre-recorded/tape playback (False). Drives Ericsson MediaFirst live playout mode and affects DAI eligibility and failover configuration.',
    `mediafirst_rundown_code` STRING COMMENT '',
    `playout_failover_mode` STRING COMMENT 'Defines the failover strategy configured in Ericsson MediaFirst if the primary playout source fails during this program. none = no failover; backup_channel = switch to backup feed; filler_loop = play filler content; manual = operator intervention required.. Valid values are `none|backup_channel|filler_loop|manual`',
    `production_format` STRING COMMENT '',
    `program_content_seconds` STRING COMMENT 'Total planned duration of editorial/program content segments in seconds, excluding commercial breaks and credits. Used for content-to-ad ratio compliance reporting.',
    `program_title` STRING COMMENT 'The editorial title of the program for which this rundown is prepared (e.g., Morning News Live, Prime Time Sports). Used for display in production systems and EPG.',
    `rights_clearance_status` STRING COMMENT '',
    `rundown_code` STRING COMMENT '',
    `rundown_notes` STRING COMMENT 'Free-text production notes associated with the rundown, capturing special instructions, last-minute changes, talent notes, or technical advisories for the production and playout teams.',
    `rundown_status` STRING COMMENT '',
    `rundown_type` STRING COMMENT '',
    `rundown_version` STRING COMMENT 'Incremental version number of the rundown, incremented each time the rundown is revised. Enables version tracking and rollback for production teams and playout automation.',
    `scheduled_end_time` TIMESTAMP COMMENT 'The planned transmission end timestamp for the program. Used to calculate total runtime and validate against EPG slot allocation.',
    `scheduled_start_time` TIMESTAMP COMMENT 'The planned transmission start timestamp for the program, including timezone offset. Used by Ericsson MediaFirst automation for playout triggering and EPG publication.',
    `scte35_cue_count` STRING COMMENT 'Number of SCTE-35 digital program insertion cue markers planned in this rundown. Used for Dynamic Ad Insertion (DAI) triggering and ad break signaling to downstream distribution systems.',
    `segment_count` STRING COMMENT 'Total number of rundown items (segments) defined in this rundown, including news blocks, interviews, commercial breaks, tosses, and credits. Used for production planning and playout validation.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this program rundown is simultaneously broadcast across multiple platforms (linear, OTT, streaming). When True, simulcast platform configurations must be applied.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `total_ad_time_seconds` STRING COMMENT 'Total planned advertising time in seconds across all ad pods in the rundown. Used for FCC/Ofcom advertising minutage compliance and Wide Orbit traffic reconciliation.',
    `total_runtime_seconds` STRING COMMENT 'Total planned duration of the program in seconds, encompassing all segments including program content, commercial breaks, and credits. Must match the EPG slot allocation.',
    `transmitted_timestamp` TIMESTAMP COMMENT 'The actual date and time when playout of this program rundown commenced transmission. Populated by Ericsson MediaFirst upon broadcast start. Used for as-run reconciliation and affidavit generation.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `wide_orbit_log_code` STRING COMMENT '',
    CONSTRAINT pk_program_rundown PRIMARY KEY(`program_rundown_id`)
) COMMENT 'Detailed production rundown for a live or studio program defining the internal segment structure — news blocks, interview segments, commercial breaks, toss segments, and closing credits. Captures program title, episode reference, total runtime, segment count, live/tape flag, rundown status, and the ordered list of rundown items with planned durations. Used by Ericsson MediaFirst automation for live show playout control and by production teams for show preparation. Supports workload modes: Linear|FAST.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`rundown_item` (
    `rundown_item_id` BIGINT COMMENT 'Unique surrogate identifier for each individual segment or item within a program rundown. Primary key for the rundown_item entity in the Databricks Silver Layer.',
    `asset_version_id` BIGINT COMMENT 'Foreign key linking to mediaasset.asset_version. Business justification: Playout automation systems require the exact asset_version_id per rundown segment to retrieve the correct encoded file from storage. Without this link, automation cannot distinguish between HD, SD, or',
    `version_id` BIGINT COMMENT 'Foreign key linking to content.version. Business justification: Each rundown item (program segment) references a specific content version for playout automation systems (e.g., Dalet, MediaFirst). Version-level tracking per segment is required for QC sign-off, as-r',
    `deal_memo_id` BIGINT COMMENT 'Foreign key linking to talent.deal_memo. Business justification: Guest and one-off talent appearances in live production rundowns are governed by deal memos rather than full contracts. Production coordinators must verify an active deal memo (deal_memo_status, engag',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to mediaasset.media_asset. Business justification: Individual rundown items (VTR, PKG, VO) must reference the specific media file for playout. Production operators need asset-level metadata (duration, timecode, format) for live show execution. Distinc',
    `profile_id` BIGINT COMMENT 'Foreign key linking to talent.talent_profile. Business justification: Individual rundown segments feature specific talent (correspondents, panelists, guests) requiring tracking for segment-level screen time calculation, residual eligibility determination, and credit att',
    `program_rundown_id` BIGINT COMMENT 'Foreign key linking to scheduling.program_rundown. Business justification: Rundown items are individual segments within a program rundown. Currently rundown_item only links to program_schedule, but it should also link to the specific program_rundown that contains it. This pr',
    `program_schedule_id` BIGINT COMMENT 'Reference to the parent program schedule (rundown header) that this item belongs to. Links the atomic rundown item to its containing broadcast schedule.',
    `role_id` BIGINT COMMENT 'Foreign key linking to talent.role. Business justification: Live production rundown items must track the specific role per segment for union/guild compliance reporting (SAG-AFTRA requires role-level appearance tracking). Role attributes (above_the_line_flag, g',
    `actual_duration_seconds` STRING COMMENT 'Real elapsed duration of the rundown item in seconds as recorded during or after playout. Compared against planned_duration_seconds for show timing analysis and as-run log reconciliation.',
    `actual_end_time` TIMESTAMP COMMENT 'Actual wall-clock time at which this rundown item completed playout. Used alongside actual_start_time to compute actual_duration_seconds and to validate show overrun or underrun conditions.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual wall-clock time at which this rundown item began playout as recorded by the Ericsson MediaFirst automation system. Used for as-run log generation and Wide Orbit affidavit reconciliation.',
    `ad_pod_duration_seconds` STRING COMMENT 'Total allocated duration in seconds for the ad pod break associated with this rundown item. Populated only when ad_pod_flag is true. Used for ad load compliance and Wide Orbit traffic scheduling.',
    `ad_pod_flag` BOOLEAN COMMENT 'Indicates whether this rundown item represents an Ad Pod (a group of commercial spots within a break). When true, triggers SCTE-35 cue marker insertion and Dynamic Ad Insertion (DAI) eligibility checks.',
    `ad_pod_spot_count` STRING COMMENT 'Number of individual commercial spots scheduled within this ad pod break. Used for ad load monitoring, Wide Orbit traffic log validation, and FCC childrens programming ad limit compliance.',
    `backtime_flag` BOOLEAN COMMENT 'Indicates whether this rundown item is backtimed — i.e., its start time is calculated backwards from a fixed end point (e.g., top-of-hour news break or programme end). Critical for live show timing control in Ericsson MediaFirst.',
    `blackout_flag` BOOLEAN COMMENT 'Indicates whether geographic broadcast blackout restrictions apply to this rundown item. When true, triggers blackout enforcement logic in the distribution layer per rights agreements managed in Rightsline.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this rundown item record was first created in the data platform, typically corresponding to the initial rundown build in Dalet Galaxy or Ericsson MediaFirst. Supports audit trail and data lineage.',
    `cue_text` STRING COMMENT 'Editorial cue or introduction text read by the presenter or director to introduce this rundown item. Stored as the production script reference for live show execution and post-broadcast archive.',
    `duration_variance_seconds` STRING COMMENT 'Difference in seconds between actual_duration_seconds and planned_duration_seconds (actual minus planned). Positive values indicate overrun; negative values indicate underrun. Used for show timing analysis and rundown optimisation.',
    `eom_timecode` STRING COMMENT 'SMPTE timecode marking the End of Message (EOM) — the precise out-point of the media asset for this rundown item. Used alongside som_timecode for frame-accurate duration calculation and playout control.. Valid values are `^d{2}:d{2}:d{2}[;:]d{2}$`',
    `epg_description` STRING COMMENT 'Short editorial description of this rundown item for display in the Electronic Program Guide (EPG). Populated for story packages and feature segments; used by EPG aggregators and on-screen guide systems.',
    `item_title` STRING COMMENT 'Human-readable editorial title or slug for the rundown item as displayed in the production control system and Electronic Program Guide (EPG). Used by producers and directors during live show execution.',
    `live_flag` BOOLEAN COMMENT 'Indicates whether this rundown item is a live production element (true) or a pre-recorded/packaged asset (false). Drives Ericsson MediaFirst automation mode selection and EPG live indicator display.',
    `planned_duration_seconds` STRING COMMENT 'Scheduled duration of the rundown item in seconds as defined during pre-production rundown preparation. Used for total show timing, backtime calculations, and ad pod compliance checks.',
    `planned_start_time` TIMESTAMP COMMENT 'Scheduled wall-clock start time for this rundown item based on the pre-production rundown. Used for Electronic Program Guide (EPG) display, backtime calculations, and SCTE-35 cue marker pre-positioning.',
    `scte35_cue_in_time` TIMESTAMP COMMENT 'Timestamp at which the SCTE-35 splice_insert cue-in signal is triggered to mark the return to programme content after an ad break. Used for DAI reconciliation and ad delivery verification.',
    `scte35_cue_out_time` TIMESTAMP COMMENT 'Timestamp at which the SCTE-35 splice_insert cue-out signal is triggered to mark the start of an ad break for Dynamic Ad Insertion (DAI) and addressable advertising systems. Populated for commercial_break item types.',
    `sequence_number` STRING COMMENT 'Ordinal position of this item within the program rundown, determining the playout order. Used by Ericsson MediaFirst automation to sequence segments during live show production control.',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this rundown item is simultaneously broadcast across multiple platforms (linear, OTT, streaming). When true, triggers multi-platform distribution workflows and DAI configuration in Akamai CDN.',
    `skip_reason` STRING COMMENT 'Reason code explaining why this rundown item was skipped during playout. Populated only when item_status = skipped. Used for post-broadcast editorial review and rights compliance audit.. Valid values are `rights_issue|technical_fault|editorial_decision|time_overrun|duplicate|not_applicable`',
    `som_timecode` STRING COMMENT 'SMPTE timecode marking the Start of Message (SOM) — the precise in-point of the media asset to be played for this rundown item. Used by Ericsson MediaFirst for frame-accurate playout cueing.. Valid values are `^d{2}:d{2}:d{2}[;:]d{2}$`',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `tape_number` STRING COMMENT 'Physical or virtual media identifier (tape ID, clip ID, or server ID) for the pre-recorded asset associated with this rundown item in the Dalet Galaxy MAM system. Used for media retrieval and playout server cueing.',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this rundown item record. Tracks editorial changes, status transitions, and timing adjustments throughout the show production lifecycle.',
    CONSTRAINT pk_rundown_item PRIMARY KEY(`rundown_item_id`)
) COMMENT 'Individual segment or item within a program rundown, representing a discrete production element (story package, live shot, interview, commercial break, graphic, music bed, or filler). Captures item sequence, item type, planned duration, actual duration, content asset reference, presenter/anchor assignment, cue text, backtime flag, and item status (ready, on-air, completed, skipped). The atomic unit of live show production control. Supports workload modes: Linear|FAST.';

CREATE OR REPLACE TABLE `vibe_media_broadcasting_v1`.`scheduling`.`channel_carriage` (
    `channel_carriage_id` BIGINT COMMENT 'Unique surrogate identifier for each channel carriage agreement record. Primary key.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to the linear broadcast channel being carried on the OTT platform',
    `delivery_channel_id` BIGINT COMMENT 'Foreign key linking to distribution.delivery_channel. Business justification: Channel carriage tracks a channels presence on an OTT platform; delivery_channel specifies the exact distribution path (FAST, SVOD, linear stream) used for that carriage. Carriage fee attribution, te',
    `ott_platform_id` BIGINT COMMENT 'Foreign key linking to the OTT platform carrying the channel',
    `territory_id` BIGINT COMMENT 'Foreign key linking to rights.rights_territory. Business justification: Channel carriage agreements are territory-specific; a channel carried on an OTT platform must comply with that territorys rights restrictions, blackout rules, and regulatory requirements. Linking cha',
    `blackout_rules_override` STRING COMMENT 'Platform-specific geographic blackout rules that override or supplement the channels default blackout_enabled configuration for this OTT platform. Explicitly identified in detection phase relationship data.',
    `carriage_fee_usd` DECIMAL(18,2) COMMENT 'The per-subscriber monthly carriage fee in US dollars that this OTT platform pays to carry this channel, which may differ from the channels default carriage_fee_usd based on negotiated terms.',
    `contract_end_date` DATE COMMENT 'The expiration or renewal date of the commercial carriage agreement. Null indicates evergreen or auto-renewing contract.',
    `contract_start_date` DATE COMMENT 'The effective start date of the commercial carriage agreement between the channel and the OTT platform.',
    `created_at` TIMESTAMP COMMENT 'Medallion lineage column: row creation timestamp',
    `dai_enabled_flag` BOOLEAN COMMENT 'Indicates whether Dynamic Ad Insertion is enabled for this channel on this specific OTT platform, overriding the channels default dai_enabled setting. Explicitly identified in detection phase relationship data.',
    `epg_sync_enabled` BOOLEAN COMMENT 'Indicates whether Electronic Program Guide data for this channel is synchronized to this OTT platforms EPG system. Explicitly identified in detection phase relationship data.',
    `platform_channel_number` STRING COMMENT 'The logical channel number assigned to this channel specifically on this OTT platform, which may differ from the channels broadcast logical_channel_number. Explicitly identified in detection phase relationship data.',
    `platform_display_name` STRING COMMENT 'The branded channel name displayed to subscribers on this specific OTT platform, which may differ from the channels network_name for branding or licensing reasons. Explicitly identified in detection phase relationship data.',
    `priority_rank` STRING COMMENT 'The display priority or prominence ranking assigned to this channel within this OTT platforms channel lineup, used for UI ordering and recommendation algorithms. Explicitly identified in detection phase relationship data.',
    `simulcast_enabled` BOOLEAN COMMENT 'Indicates whether this channel is configured for simultaneous multi-platform broadcast (simulcast). When true, the channels linear feed is distributed concurrently across broadcast, cable, and OTT/streaming platforms. [Moved from channel: This boolean flag on the channel product indicates whether the channel is configured for simulcast, but the actual simulcast configuration is platform-specific. The flag should remain on channel as a capability indicator, but the actual simulcast implementation details (start/end dates, platform-specific settings) belong in the carriage association. However, upon review, this attribute can remain on channel as a general capability flag - no move required.]',
    `simulcast_end_date` DATE COMMENT 'The date on which this channel ceased or will cease simulcast distribution on this OTT platform. Null indicates ongoing carriage. Explicitly identified in detection phase relationship data.',
    `simulcast_start_date` DATE COMMENT 'The date on which this channel began or will begin simulcast distribution on this OTT platform. Explicitly identified in detection phase relationship data.',
    `source_code` STRING COMMENT 'Medallion lineage column: natural id in source system',
    `updated_at` TIMESTAMP COMMENT 'Medallion lineage column: row last update timestamp',
    CONSTRAINT pk_channel_carriage PRIMARY KEY(`channel_carriage_id`)
) COMMENT 'This association product represents the carriage contract between a linear broadcast channel and an OTT platform. It captures the commercial and technical terms under which a specific channel is distributed on a specific OTT platform. Each record links one channel to one OTT platform with platform-specific configurations including simulcast timing, channel positioning, branding overrides, ad insertion rules, and blackout policies that exist only in the context of this distribution relationship.. Existence Justification: In media broadcasting operations, linear broadcast channels are distributed across multiple OTT platforms simultaneously (e.g., CNN appears on Hulu, YouTube TV, Peacock, Sling), and each OTT platform carries dozens to hundreds of channels in its lineup. Each channel-platform pairing requires a distinct carriage agreement with platform-specific commercial terms (carriage fees, contract dates) and technical configurations (channel numbering, branding, DAI settings, blackout overrides, EPG sync). The business actively manages these carriage agreements as operational contracts. Supports workload modes: MVPD|Retransmission.';

